import { NextResponse } from "next/server";
import nodemailer from "nodemailer";

export async function POST(req: Request) {
  try {
    const { name, email, phone, helpType, message, location, lat, lng } = await req.json();

    const transporter = nodemailer.createTransport({
      host: "smtp.gmail.com",
      port: 587,
      secure: false,
      auth: {
        user: process.env.EMAIL_USER,
        pass: process.env.EMAIL_PASS,
      },
    });

    const coordinatesStr = lat && lng ? `${lat}, ${lng}` : 'Not provided';

    const mailOptions = {
      from: process.env.EMAIL_USER,
      to: "harinithamg03@gmail.com",
      subject: "New Disaster Help Request",
      text: `New Disaster Help Request\n\nName: ${name}\nPhone: ${phone}\nHelp Needed: ${helpType}\nLocation: ${location}\nMessage: ${message}\nCoordinates: ${coordinatesStr}`,
      html: `
        <div style="font-family: sans-serif; padding: 20px; color: #333;">
          <h2 style="color: #ef4444;">New Disaster Help Request</h2>
          <p><strong>Name:</strong> ${name}</p>
          <p><strong>Phone:</strong> ${phone}</p>
          <p><strong>Help Needed:</strong> ${helpType}</p>
          <p><strong>Location:</strong> ${location}</p>
          <p><strong>Message:</strong> ${message}</p>
          <p><strong>Coordinates:</strong> ${coordinatesStr}</p>
        </div>
      `,
    };

    // Ensure the email is sent using Nodemailer. 
    // In development without credentials, this will throw an error caught below.
    try {
      await transporter.sendMail(mailOptions);
      console.log("Email sent successfully");
    } catch (error) {
      console.log("Email error:", error);
      return NextResponse.json({ success: false, error: "Failed to send email" }, { status: 500 });
    }

    return NextResponse.json({ 
      success: true, 
      message: "Your help request has been sent. Rescue team will contact you soon." 
    });

  } catch (error) {
    console.error("Help request error:", error);
    return NextResponse.json({ success: false, error: "Failed to send help request" }, { status: 500 });
  }
}

import { NextResponse } from "next/server";
import { auth } from "@/auth";
import { prisma } from "@/lib/prisma";

export async function GET() {
  try {
    const requests = await prisma.helpRequest.findMany({
      orderBy: { createdAt: "desc" },
      include: { requester: true }
    });

    const mappedRequests = requests.map(req => ({
      ...req, // Keep original fields for backward compatibility (Map.tsx)
      latitude: req.lat,
      longitude: req.lng,
      location: req.locationName,
      helpType: req.type,
      name: req.requester?.name || "Unknown User",
      message: req.description
    }));

    return NextResponse.json(mappedRequests);
  } catch (error) {
    console.error("Failed to fetch requests:", error);
    return NextResponse.json({ error: "Failed to fetch requests" }, { status: 500 });
  }
}

export async function POST(req: Request) {
  try {
    const session = await auth();
    const data = await req.json();

    // Smart Priority Scoring (Initial Logic)
    let priorityScore = 0;
    if (data.urgency === "CRITICAL") priorityScore += 50;
    if (data.urgency === "HIGH") priorityScore += 30;
    priorityScore += Math.min(data.peopleAffected * 5, 50);

    const helpRequest = await prisma.helpRequest.create({
      data: {
        requesterId: session?.user?.id || null,
        lat: data.lat,
        lng: data.lng,
        type: data.type,
        description: data.description,
        urgency: data.urgency,
        peopleAffected: data.peopleAffected,
        priorityScore: priorityScore,
        status: "PENDING",
      },
    });

    return NextResponse.json(helpRequest, { status: 201 });
  } catch (error) {
    return NextResponse.json({ error: "Failed to create request" }, { status: 500 });
  }
}

import { NextResponse } from "next/server";
import { prisma } from "@/lib/prisma";

export async function POST(req: Request) {
  try {
    const { name, email, password, role } = await req.json();

    const existingUser = await prisma.user.findUnique({
      where: { email },
    });

    if (existingUser) {
      return NextResponse.json({ error: "User already exists" }, { status: 400 });
    }

    const user = await prisma.user.create({
      data: {
        name,
        email,
        password, // Reminder: Plain password for hackathon demo. Use bcrypt in production.
        role,
      },
    });

    return NextResponse.json({ user: { id: user.id, email: user.email } }, { status: 201 });
  } catch (error) {
    return NextResponse.json({ error: "Something went wrong" }, { status: 500 });
  }
}

import { auth } from "@/auth";
import { prisma } from "@/lib/prisma";
import { BarChart3, TrendingUp, Users, Package, AlertCircle } from "lucide-react";

async function getAnalytics() {
  const [totalRequests, activeVolunteers, criticalRequests, completedRequests] = await Promise.all([
    prisma.helpRequest.count(),
    prisma.user.count({ where: { role: "VOLUNTEER" } }),
    prisma.helpRequest.count({ where: { urgency: "CRITICAL" } }),
    prisma.helpRequest.count({ where: { status: "COMPLETED" } }),
  ]);

  return { totalRequests, activeVolunteers, criticalRequests, completedRequests };
}

