function MetricCard({ title, value, icon, trend }: any) {
  return (
    <div style={{ background: "var(--card-bg)", padding: "1.5rem", borderRadius: "1.25rem", border: "1px solid var(--border)" }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: "1rem" }}>
        <div style={{ padding: "0.5rem", background: "rgba(255,255,255,0.05)", borderRadius: "0.75rem" }}>{icon}</div>
        <span style={{ fontSize: "0.75rem", color: "var(--text-muted)" }}>{trend}</span>
      </div>
      <p style={{ fontSize: "0.875rem", color: "var(--text-muted)", marginBottom: "0.25rem" }}>{title}</p>
      <p style={{ fontSize: "2rem", fontWeight: "700" }}>{value}</p>
    </div>
  );
}

function CategoryBar({ label, percentage, color }: any) {
  return (
    <div>
      <div style={{ display: "flex", justifyContent: "space-between", fontSize: "0.875rem", marginBottom: "0.4rem" }}>
        <span>{label}</span>
        <span>{percentage}%</span>
      </div>
      <div style={{ height: "8px", background: "rgba(255,255,255,0.1)", borderRadius: "4px", overflow: "hidden" }}>
        <div style={{ width: `${percentage}%`, height: "100%", background: color }}></div>
      </div>
    </div>
  );
}

"use client";

import { useSession } from "next-auth/react";
import Sidebar from "@/components/Sidebar";
import { redirect } from "next/navigation";
import { useState } from "react";

export default function DashboardLayout({
  children,
}: {
  children: React.ReactNode;
}) {
  const { data: session, status } = useSession();
  const [lowBandwidth, setLowBandwidth] = useState(false);

  if (status === "loading") return null;
  if (!session) {
    redirect("/login");
  }

  const role = (session.user as any)?.role || "VICTIM";

  return (
    <div className={`dashboard-layout ${lowBandwidth ? "low-bandwidth" : ""}`}>
      <Sidebar role={role} />
      <main className="main-content">
        <div style={{ 
          marginBottom: "1rem", 
          display: "flex", 
          justifyContent: "flex-end",
          fontSize: "0.75rem" 
        }}>
          <label style={{ display: "flex", alignItems: "center", gap: "0.5rem", cursor: "pointer", color: "var(--text-muted)" }}>
            <input 
              type="checkbox" 
              checked={lowBandwidth} 
              onChange={() => setLowBandwidth(!lowBandwidth)} 
            />
            Low-Bandwidth Mode
          </label>
        </div>
        {children}
      </main>

      <style jsx global>{`
        .low-bandwidth * {
          background-image: none !important;
          animation: none !important;
          transition: none !important;
        }
        .low-bandwidth body {
          background: #000 !important;
        }
        .low-bandwidth img, .low-bandwidth .logo-icon {
          display: none !important;
        }
      `}</style>
    </div>
  );
}

import { auth } from "@/auth";
import SOSButton from "@/components/SOSButton";
import { prisma } from "@/lib/prisma";
import { 
  Users, 
  MapPin, 
  Package, 
  CheckCircle2 
} from "lucide-react";

async function getStats() {
  const [requestCount, volunteerCount, activeSOS] = await Promise.all([
    prisma.helpRequest.count({ where: { status: "PENDING" } }),
    prisma.user.count({ where: { role: "VOLUNTEER" } }),
    prisma.helpRequest.count({ where: { type: "SOS", status: "PENDING" } }),
  ]);

  return { requestCount, volunteerCount, activeSOS };
}

